import React, { useState } from 'react';
import { streamxApi } from '../services/api';

export default function PricingPage() {
  const [error, setError] = useState('');

  const checkout = async (plan) => {
    setError('');
    try {
      const res = await streamxApi.createCheckout(plan);
      if (res.data?.url) {
        window.location.href = res.data.url;
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Unable to start checkout');
    }
  };

  return (
    <main style={{ paddingTop: '96px', padding: '96px 24px 24px' }}>
      <h1 style={{ marginBottom: '16px' }}>Pricing</h1>
      {error && <p style={{ color: '#ff6b6b' }}>{error}</p>}
      <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
        <button className='btn' onClick={() => checkout('basic')}>Basic - $9.99</button>
        <button className='btn btn-red' onClick={() => checkout('premium')}>Premium - $19.99</button>
      </div>
    </main>
  );
}
